## API Routes (Pages Router)

API routes in the Pages Router use handler functions in the `pages/api/` directory.

### Basic Handler

```tsx
// pages/api/hello.ts
import type { NextApiRequest, NextApiResponse } from 'next'

export default function handler(
  req: NextApiRequest,
  res: NextApiResponse
) {
  if (req.method === 'GET') {
    res.status(200).json({ message: 'Hello' })
  } else if (req.method === 'POST') {
    const { name } = req.body
    res.status(201).json({ message: `Created ${name}` })
  } else {
    res.setHeader('Allow', ['GET', 'POST'])
    res.status(405).end(`Method ${req.method} Not Allowed`)
  }
}
```

### Dynamic API Routes

```tsx
// pages/api/posts/[id].ts
import type { NextApiRequest, NextApiResponse } from 'next'

export default async function handler(
  req: NextApiRequest,
  res: NextApiResponse
) {
  const { id } = req.query

  switch (req.method) {
    case 'GET':
      const post = await getPost(id as string)
      return res.json(post)
    case 'DELETE':
      await deletePost(id as string)
      return res.status(204).end()
    default:
      res.setHeader('Allow', ['GET', 'DELETE'])
      return res.status(405).end()
  }
}
```

### Custom Config

```tsx
// pages/api/upload.ts
export const config = {
  api: {
    bodyParser: false,        // Disable built-in body parsing
    responseLimit: '8mb',     // Increase response size limit
    externalResolver: true,   // Suppress "API resolved without response" warning
  },
}
```

## Environment Variables

| Variable | Purpose |
|----------|----------|
| `NEXT_PUBLIC_API_URL` | Public API base URL (exposed to browser) |
| `DATABASE_URL` | Database connection string (server only) |
| `WEBHOOK_SECRET` | Webhook signature verification secret (server only) |
